import { useEffect, useState } from 'react';
import { useAuth } from './hooks/useAuth';
import { db } from './firebase/firebase';
import { collection, onSnapshot, query, where, orderBy, addDoc, updateDoc, deleteDoc, doc, setDoc } from 'firebase/firestore';
import { User } from 'firebase/auth'; // Import User from firebase/auth
import { Theme } from './types';
import './App.css';
import './index.css';
import { AnimeSearch } from './components/AnimeSearch';
import { AnimeCard } from './components/AnimeCard';
import { StatsBoard } from './components/StatsBoard';
import { ThemeToggle } from './components/ThemeToggle';
import { Loader2, LogIn, LogOut, Tv } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [watchlist, setWatchlist] = useState<WatchListEntry[]>([]);
  const [history, setHistory] = useState<WatchHistoryItem[]>([]);
  const [theme, setTheme] = useState<Theme>(Theme.SAKURA);

  // Auth Form State
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isSignUp, setIsSignUp] = useState(false);
  const [error, setError] = useState('');

  // 1. Theme Initialization
  useEffect(() => {
    if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
      setTheme(Theme.MIDNIGHT);
    }
  }, []);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (user) => {
      setUser(user);
      setAuthLoading(false);
    });

    return () => unsubscribe();
  }, []);


  const handleAuth = async () => {
    setError('');
    try {
      if (isSignUp) {
        await createUserWithEmailAndPassword(auth, email, password);
      } else {
        await signInWithEmailAndPassword(auth, email, password);
      }
    } catch (e: any) {
      setError(e.message);
    }
  };

  const handleLogout = async () => {
    setError('');
    try {
      await signOut(auth);
    } catch (e: any) {
      setError(e.message);
    }
  };

  useEffect(() => {
    if (!user) return;

    const watchlistQuery = query(collection(db, 'watchlists'), where('userId', '==', user.uid), orderBy('addedAt', 'desc'));
    const historyQuery = query(collection(db, 'watchHistories'), where('userId', '==', user.uid), orderBy('watchedAt', 'desc'));

    const watchlistUnsubscribe = onSnapshot(watchlistQuery, (snapshot) => {
      const newWatchlist = snapshot.docs.map((doc) => ({
        id: doc.id,
        ...(doc.data() as Omit<WatchListEntry, 'id'>)
      }));
      setWatchlist(newWatchlist);
    });

    const historyUnsubscribe = onSnapshot(historyQuery, (snapshot) => {
      const newHistory = snapshot.docs.map((doc) => ({
        id: doc.id,
        ...(doc.data() as Omit<WatchHistoryItem, 'id'>)
      }));
      setHistory(newHistory);
    });

    return () => {
      watchlistUnsubscribe();
      historyUnsubscribe();
    };
  }, [user]);

  const addAnimeToWatchlist = async (anime: Anime) => {
    if (!user) return;
    try {
      const docRef = await addDoc(collection(db, 'watchlists'), {
        userId: user.uid,
        malId: anime.mal_id,
        title: anime.title,
        imageUrl: anime.images.jpg.image_url,
        addedAt: new Date(),
      });


