<changes>
  <change>
    <file>components/AnimeSearch.tsx</file>
    <description>Add a visible 'Add' button to each search result item that triggers the add action</description>
    <content><![CDATA[import React, { useState, useEffect, useCallback } from 'react';
import { Search, Plus, Loader2 } from 'lucide-react';
import { searchAnime } from '../services/jikanService';
import { Anime } from '../types';

interface AnimeSearchProps {
  onAddAnime: (anime: Anime, watched: number) => void;
}

export const AnimeSearch: React.FC<AnimeSearchProps> = ({ onAddAnime }) => {
  const [query, setQuery] = useState('');
  const [animeList, setAnimeList] = useState<Anime[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSearch = useCallback(async (query: string) => {
    if (!query) {
      setAnimeList([]);
      setError(null);
      return;
    }
    setLoading(true);
    setError(null);
    try {
      const results = await searchAnime(query);
      setAnimeList(results);
    } catch (error: any) {
      console.error('Error searching anime:', error);
      setError(error.message || 'Failed to search for anime');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    const timer = setTimeout(() => {
      handleSearch(query);
    }, 300);
    return () => clearTimeout(timer);
  }, [query, handleSearch]);

  const handleSelect = (anime: Anime) => {
    onAddAnime(anime, 0);
  };

  return (
    <div className="w-full h-full flex flex-col items-center">
      <div className="w-full max-w-2xl p-4">
        <div className="flex items-center space-x-2">
          <Search className="h-4 w-4 text-gray-400" />
          <input
            type="text"
            className="w-full bg-transparent outline-none border-b-2 border-gray-700 py-1"
            placeholder="Search anime..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
          />
        </div>
      </div>

      {loading && <Loader2 className="animate-spin h-5 w-5" />}

      {error && <p className="text-red-500">{error}</p>}

      <div className="w-full max-w-2xl px-4 py-2">
        {animeList.map((anime) => (
          <div
            key={anime.mal_id}
            className="flex items-center justify-between p-2 hover:bg-gray-800 rounded-md"
          >
            <div className="flex items-center space-x-2 w-full" onClick={() => handleSelect(anime)}>
              <img src={anime.images.jpg.image_url} alt={anime.title} className="h-12 w-8" />
              <span>{anime.title}</span>
            </div>
            <button
              onClick={(e) => {
                e.stopPropagation();
                handleSelect(anime);
              }}
              className="px-2 py-1 rounded-md bg-blue-500 text-white hover:bg-blue-600"
            >
              Add
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};
]]></content>
  </change>
</changes>
